class FirstOrderHold(_ShimBlock):
    """
    First-order hold reconstructor.

    Reconstructs a continuous signal from periodic samples using linear
    extrapolation across one sampling interval. Causal (one-sample-lag)
    variant matching the Simulink ``First-Order Hold`` block.

    Between two consecutive sample times :math:`t_{k-1}` and :math:`t_k`,
    the output is

    .. math::

        y(t) = u_{k-1} + \\frac{u_{k-1} - u_{k-2}}{T} (t - t_{k-1})

    During the very first interval (only one sample captured) the output
    is held at the most recent sample.

    Note
    ----
    Supports vector input — each channel is extrapolated independently.

    Parameters
    ----------
    T : float
        sampling period
    tau : float
        delay before first sample

    Attributes
    ----------
    events : list[Schedule]
        internal scheduled event for periodic sampling
    """
    _factory_name = "FirstOrderHold"
    _param_defaults = {'T': None, 'tau': None}
    input_port_labels = None
    output_port_labels = None
    def __init__(self, T=..., tau=...):
        super().__init__()
        self._shim_init({"T": T, "tau": tau})


class FullyImplicitDAE(_JitShimBlock):
    """
    Fully-implicit DAE block.

    For systems that can't be cast into semi-explicit or mass-matrix form —
    implicit constitutive relations, mixed differential/algebraic with
    non-trivial coupling — the residual form

    .. math::

        F(x, \\dot{x}, u, t) = 0, \\quad y = x

    is solved directly. Only implicit solvers (ESDIRK/DIRK family) work; the
    block installs a fully-implicit stage builder into the engine via the
    post-processing hook.

    The JIT path traces `func` and derives both
    :math:`\\partial F / \\partial x` and :math:`\\partial F / \\partial \\dot{x}`
    via auto-differentiation when no analytical Jacobians are supplied.
    Index-1 systems (singular :math:`\\partial F / \\partial \\dot{x}`):
    prefer DIRK over ESDIRK for stability.

    Parameters
    ----------
    func : callable
        residual ``F(x, xdot, u, t) -> ndarray``
    initial_value : array_like
        consistent :math:`x_0`. The caller is responsible for choosing it such
        that there exists an :math:`\\dot{x}_0` with
        :math:`F(x_0, \\dot{x}_0, u_0, 0) \\approx 0`.
    jac_x : callable, optional
        analytical :math:`\\partial F / \\partial x` as a flat row-major
        ``n × n`` array. Falls back to numerical (central differences) if
        omitted.
    jac_xdot : callable, optional
        analytical :math:`\\partial F / \\partial \\dot{x}` as a flat row-major
        ``n × n`` array. Falls back to numerical (central differences) if
        omitted.
    """
    _factory_name = "FullyImplicitDAE"
    _param_defaults = {'func': None, 'initial_value': None, 'jac_x': None, 'jac_xdot': None}
    _jit_fn = staticmethod(_jit_fully_implicit)
    _adapt_func = False
    input_port_labels = None
    output_port_labels = None
    def __init__(self, func=None, initial_value=None, jac_x=None, jac_xdot=None):
        super().__init__()
        self._jit_init({"func": func, "initial_value": initial_value, "jac_x": jac_x, "jac_xdot": jac_xdot})


class Function(_JitShimBlock):
    """
    Arbitrary MIMO function block, defined by a function or `lambda` expression.

    The function can have multiple arguments that are then provided
    by the input channels of the function block.

    Form multi input, the function has to specify multiple arguments
    and for multi output, the aoutputs have to be provided as a
    tuple or list.

    In the context of the global system, this block implements algebraic
    components of the global system ODE/DAE.

    .. math::

        \\vec{y} = \\mathrm{func}(\\vec{u})


    Note
    ----
    This block is purely algebraic and its operation (`op_alg`) will be called
    multiple times per timestep, each time when `Simulation._update(t)` is
    called in the global simulation loop.
    Therefore `func` must be purely algebraic and not introduce states,
    delay, etc. For interfacing with external stateful APIs, use the
    `Wrapper` block.


    Note
    -----
    If the outputs are provided as a single numpy array, they are
    considered a single output. For MIMO, output has to be tuple.


    Example
    -------
    consider the function:

    .. code-block:: python

        from pathsim.blocks import Function

        def f(a, b, c):
            return a**2, a*b, b/c

        fn = Function(f)


    then, when the block is updated, the input channels of the block are
    assigned to the function arguments following this scheme:

    .. code-block::

        inputs[0] -> a
        inputs[1] -> b
        inputs[2] -> c

    and the function outputs are assigned to the
    output channels of the block in the same way:

    .. code-block::

        a**2 -> outputs[0]
        a*b  -> outputs[1]
        b/c  -> outputs[2]

    Because the `Function` block only has a single argument, it can be
    used to decorate a function and make it a `PathSim` block. This might
    be handy in some cases to keep definitions concise and localized
    in the code:

    .. code-block:: python

        from pathsim.blocks import Function

        #does the same as the definition above

        @Function
        def fn(a, b, c):
            return a**2, a*b, b/c

        #'fn' is now a PathSim block


    Parameters
    ----------
    func : callable
        MIMO function that defines algebraic block IO behaviour, signature `func(*tuple)`


    Attributes
    ----------
    op_alg : Operator
        internal algebraic operator that wraps `func`
    """
    _factory_name = "Function"
    _param_defaults = {'func': None}
    _jit_fn = staticmethod(_jit_function)
    _adapt_func = True
    input_port_labels = None
    output_port_labels = None
